n task.wait(0.5) continue end irA(root, p) if i == #ruta then task.wait(1) end end end end local function activarFarm() if farmOn then return end farmOn = true farmThread = task.spawn(loopFarm) end local function desactivarFarm() farmOn = false end local VirtualUser = game:GetService("VirtualUser") local antiAfkOn = false local function activarAntiAfk() antiAfkOn = true plr.Idled:Connect(function() if antiAfkOn then VirtualUser:CaptureController() VirtualUser:ClickButton2(Vector2.new()) end end) end local function desactivarAntiAfk() antiAfkOn = false end local EXACT_NAMES_TO_DESTROY = { "MovingWall1", "MovingWall2", "MovingWall3", "MovingWall4", "MovingWall5", "MovingWall6", "MovingWall7", "MovingWall8", "MovingWall9", "MovingWalls", "LavaPart", "NPC5_AttackZone", "NPC9_AttackZone", "Piques", "piques", "Movement", "Tsunami", "TsunamiEnd", "TsunamiSpawn", "TriggerPart", "Twomp", "Twomps", "Ventilateurs", "FanEffects", } local function quitarLava() for _, nombre in ipairs(EXACT_NAMES_TO_DESTROY) do for _, obj in ipairs(workspace:GetDescendants()) do if obj.Name == nombre then obj:Destroy() end end end end local conexionFuente = nil local function aplicarFuenteInstancia(inst, rutaFuente) if inst:IsA("TextLabel") or inst:IsA("TextButton") or inst:IsA("TextBox") then pcall(function() local pesoActual = Enum.FontWeight.Regular local estiloActual = Enum.FontStyle.Normal local ok, fontFaceActual = pcall(function() return inst.FontFace end) if ok and fontFaceActual then pesoActual = fontFaceActual.Weight estiloActual = fontFaceActual.Style end inst.FontFace = Font.new(rutaFuente, pesoActual, estiloActual) end) end end local function aplicarFuenteJuego(rutaFuente) if conexionFuente then conexionFuente:Disconnect() conexionFuente = nil end for _, inst in ipairs(game:GetDescendants()) do aplicarFuenteInstancia(inst, rutaFuente) end conexionFuente = game.DescendantAdded:Connect(function(inst) aplicarFuenteInstancia(inst, rutaFuente) end) end local conexionColorTexto = nil local